/**
 * MNQ close for a trade date. Falls back to the most recent prior session
 * (covers weekends/holidays). Returns null only when the date precedes all
 * data. Dates after the last session resolve to the last session's close.
 */
export function mnqCloseForDate(isoDate: string | null): number | null {
  if (!isoDate) return null;
  const arr = MNQ_DAILY_CLOSES;
  if (arr.length === 0) return null;
  if (isoDate < arr[0][0]) return null;
  if (isoDate >= arr[arr.length - 1][0]) return arr[arr.length - 1][1];
  // Binary search for the latest entry whose date <= isoDate.
  let lo = 0;
  let hi = arr.length - 1;
  let ans = 0;
  while (lo <= hi) {
    const mid = (lo + hi) >> 1;
    if (arr[mid][0] <= isoDate) {
      ans = mid;
      lo = mid + 1;
    } else {
      hi = mid - 1;
    }
  }
  return arr[ans][1];
}

/** First and last session dates available, for UI hints. */
export const MNQ_PRICE_RANGE = {
  first: MNQ_DAILY_CLOSES[0][0],
  last: MNQ_DAILY_CLOSES[MNQ_DAILY_CLOSES.length - 1][0],
} as const;
